() => {
    const results = [];

    // Find visible buttons
    const buttons = document.querySelectorAll('button, [role="button"], a[class*="btn"], div[class*="btn"]');
    buttons.forEach((el, i) => {
        const rect = el.getBoundingClientRect();
        if (rect.width > 0 && rect.height > 0) {
            const text = (el.textContent || '').trim().substring(0, 50);
            const tag = el.tagName.toLowerCase();
            const classes = el.className ? String(el.className).substring(0, 80) : '';
            const id = el.id || '';
            results.push({
                type: 'button',
                index: results.length,
                tag: tag,
                text: text,
                classes: classes,
                id: id,
                selector: id ? `#${id}` : (classes ? `${tag}.${String(el.className).split(' ')[0]}` : `${tag}:nth-of-type(${i+1})`),
            });
        }
    });

    // Find visible textareas and contenteditable elements

